def create_svg_icon(svg_string, width=24, height=24):
    renderer = QSvgRenderer(QByteArray(svg_string.encode('utf-8')))
    pixmap = QPixmap(width, height)
    pixmap.fill(Qt.GlobalColor.transparent)
    painter = QPainter(pixmap)
    painter.setRenderHint(QPainter.RenderHint.Antialiasing)
    renderer.render(painter)
    painter.end()
    return QIcon(pixmap)

def apply_dark_titlebar(window):
    try:
        import ctypes
        hwnd = int(window.winId())
        val = ctypes.c_int(1)
        # Windows 11 and Windows 10 build 19041+
        ctypes.windll.dwmapi.DwmSetWindowAttribute(
            ctypes.c_void_p(hwnd), ctypes.c_int(20), ctypes.byref(val), ctypes.sizeof(val)
        )
        # Windows 10 older builds
        ctypes.windll.dwmapi.DwmSetWindowAttribute(
            ctypes.c_void_p(hwnd), ctypes.c_int(19), ctypes.byref(val), ctypes.sizeof(val)
        )
    except Exception:
        pass
